  it('appends query params correctly', () => {
    expect(buildApiUrl('/users', { role: 'admin' })).toContain('role=admin')
  })
  it('falls back to localhost when env is unset', () => {
    expect(buildApiUrl('/ping')).toMatch(/localhost:3000/)
  })
}

// Intercept, alias, stub, and assert — works across Chrome, Firefox, Edge
cy.intercept('POST', '/api/search', (req) => {
  req.alias = 'searchReq';
  req.reply({
    statusCode: 200,
    body: { results: [{ id: 1, title: 'Cypress Rocks' }] },
    delay: 100,
  });
});

cy.get('[data-cy=search-input]').type('Cypress');
